                        // Add field mapping definitions here
                      }
                    }
                    // ... additional sub-fields 
                  }
                }
              }
            }
            // ... additional fields 
          }
        }
      }
    },
    { "typeSets", new BsonArray
      {
        new BsonDocument
        {
          { "name", "<type-set-name>" },
          { "types", new BsonArray
            {
              new BsonDocument
              {
                { "type", "<field-type>" }
                // ... field type configuration 
              }
              // ... additional types 
            }
          }
        }
